import React, { useEffect, useState } from 'react';
import { api } from '../utils/api';

export default function MapTlemcen() {
  const [patientsByCommune, setPatientsByCommune] = useState({});
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchPatientsData = async () => {
      try {
        const patients = await api.getPatients();
        // Grouper les patients par commune
        const grouped = patients.reduce((acc, patient) => {
          const commune = patient.commune || 'Non spécifiée';
          if (!acc[commune]) {
            acc[commune] = [];
          }
          acc[commune].push(patient);
          return acc;
        }, {});
        setPatientsByCommune(grouped);
      } catch (error) {
        console.error('Erreur lors du chargement des patients:', error);
      } finally {
        setLoading(false);
      }
    };

    fetchPatientsData();
  }, []);

  const totalPatients = Object.values(patientsByCommune).reduce((sum, patients) => sum + patients.length, 0);
  const communesCount = Object.keys(patientsByCommune).length;
  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Carte SIG Tlemcen</h1>
          <p className="page-subtitle">Système d'information géographique de la wilaya de Tlemcen</p>
        </div>
      </div>

      <div className="card" style={{ height: '600px', padding: 0, overflow: 'hidden' }}>
        <iframe
          src="https://www.google.com/maps/embed?pb=!1m18!1m12!1m3!1d3279.999!2d-1.315!3d34.878!2m3!1f0!2f0!3f0!3m2!1i1024!2i768!4f13.1!3m3!1m2!1s0x1281b8b8b8b8b8b8b%3A0x1234567890abcdef!2sTlemcen%2C%20Algeria!5e0!3m2!1sen!2s!4v1703123456789!5m2!1sen!2s"
          width="100%"
          height="100%"
          style={{ border: 0 }}
          allowFullScreen=""
          loading="lazy"
          referrerPolicy="no-referrer-when-downgrade"
          title="Carte de Tlemcen"
        ></iframe>
      </div>

      <div className="grid grid-3" style={{ marginTop: '24px' }}>
        <div className="card">
          <div className="card-header">
            <h3>Informations géographiques</h3>
          </div>
          <div className="card-content">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              <div>
                <div style={{ fontWeight: 600, color: 'var(--text-muted)', fontSize: '12px' }}>WILAYA</div>
                <div style={{ fontSize: '16px', fontWeight: 600 }}>Tlemcen (13)</div>
              </div>
              <div>
                <div style={{ fontWeight: 600, color: 'var(--text-muted)', fontSize: '12px' }}>SUPERFICIE</div>
                <div style={{ fontSize: '16px', fontWeight: 600 }}>9 061 km²</div>
              </div>
              <div>
                <div style={{ fontWeight: 600, color: 'var(--text-muted)', fontSize: '12px' }}>POPULATION</div>
                <div style={{ fontSize: '16px', fontWeight: 600 }}>949 135 hab.</div>
              </div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">
            <h3>Centres de vaccination</h3>
          </div>
          <div className="card-content">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: 'var(--success)' }}></div>
                <span>Centre Hospitalier Tlemcen</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: 'var(--accent)' }}></div>
                <span>CHU Nedroma</span>
              </div>
              <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                <div style={{ width: '8px', height: '8px', borderRadius: '50%', background: 'var(--accent3)' }}></div>
                <span>Centre de Maghnia</span>
              </div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="card-header">
            <h3>Statistiques</h3>
          </div>
          <div className="card-content">
            <div style={{ display: 'flex', flexDirection: 'column', gap: '12px' }}>
              <div>
                <div style={{ fontWeight: 600, color: 'var(--text-muted)', fontSize: '12px' }}>TAUX DE COUVERTURE</div>
                <div style={{ fontSize: '24px', fontWeight: 800, color: 'var(--success)' }}>87.3%</div>
              </div>
              <div>
                <div style={{ fontWeight: 600, color: 'var(--text-muted)', fontSize: '12px' }}>POPULATION VACCINÉE</div>
                <div style={{ fontSize: '20px', fontWeight: 600 }}>827 542</div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
